A debounce function delays invoking your callback until a specified wait time has passed with no new calls.

```javascript
// debounce.js
function debounce(fn, wait = 300) {
  let t;
  return function (...args) {
    clearTimeout(t);
    t = setTimeout(() => fn.apply(this, args), wait);
  };
}

/* ---- usage ---- */
const log = debounce(() => console.log('Resized!'), 400);
window.addEventListener('resize', log);
```
